import{_ as e,o,c as s,a0 as t}from"./chunks/framework.BjpW4enL.js";const h=JSON.parse('{"title":"ADR: Transição para Topologia T4 Esparsa (k-NN)","description":"","frontmatter":{},"headers":[],"relativePath":"Z_Archive/wiki_legacy/archive/legacy_pre_federation/research/SPARSE_TOPOLOGY_T4.md","filePath":"Z_Archive/wiki_legacy/archive/legacy_pre_federation/research/SPARSE_TOPOLOGY_T4.md","lastUpdated":1782593311000}'),i={name:"Z_Archive/wiki_legacy/archive/legacy_pre_federation/research/SPARSE_TOPOLOGY_T4.md"};function r(n,a,l,c,d,p){return o(),s("div",null,[...a[0]||(a[0]=[t('<h1 id="adr-transicao-para-topologia-t4-esparsa-k-nn" tabindex="-1">ADR: Transição para Topologia T4 Esparsa (k-NN) <a class="header-anchor" href="#adr-transicao-para-topologia-t4-esparsa-k-nn" aria-label="Permalink to &quot;ADR: Transição para Topologia T4 Esparsa (k-NN)&quot;">​</a></h1><p><strong>Status</strong>: Aceito e Implementado (Prototipado)<br><strong>Date</strong>: 2026-03-14</p><h2 id="contexto" tabindex="-1">Contexto <a class="header-anchor" href="#contexto" aria-label="Permalink to &quot;Contexto&quot;">​</a></h2><p>A camada T4 do NEXUS (Grafo) baseava-se em um script Python batch (<code>scripts/nexus_topology.py</code>) que calculava a tensão topológica (<code>hilbert_stress</code>) entre todos os pares de nós L0 do sistema.</p><p>A complexidade computacional dessa operação era <strong>$O(N^2)$</strong>. Para 2.400 nós, isso significava ~5.8 milhões de arestas potenciais e comparações espaciais. Para 100.000 nós, a computação se tornaria insustentável localmente (10 bilhões de cálculos), arruinando o tempo real e a interatividade do assistente.</p><h2 id="decisao" tabindex="-1">Decisão <a class="header-anchor" href="#decisao" aria-label="Permalink to &quot;Decisão&quot;">​</a></h2><ol><li>Abandonar o cálculo batch global $O(N^2)$ das arestas de <code>stress</code>.</li><li>Adotar a construção de um <strong>Grafo Esparso (K-Nearest Neighbors)</strong> utilizando o índice HNSW nativo da base vetorial T3 (Qdrant).</li><li>A cada inserção ou atualização no grafo (ou através do script de manutenção <code>build_sparse_topology.py</code>), o sistema consulta o Qdrant pelos $K$ vizinhos mais próximos (Ex: $K=5$).</li><li>Arestas topológicas (<code>hilbert_bridge</code>) são inseridas apenas entre esses k-vizinhos, convertendo a complexidade para <strong>$O(K \\log N)$</strong> iterativo.</li></ol><h2 id="consequencias" tabindex="-1">Consequências <a class="header-anchor" href="#consequencias" aria-label="Permalink to &quot;Consequências&quot;">​</a></h2><h3 id="positivo" tabindex="-1">Positivo <a class="header-anchor" href="#positivo" aria-label="Permalink to &quot;Positivo&quot;">​</a></h3><ul><li>Resolução imediata do gargalo computacional: O grafo T4 cresce organicamente sem escalar o custo de forma quadrática.</li><li>Uso eficiente da infraestrutura: O Qdrant já calcula k-NN de forma sub-linear.</li></ul><h3 id="negativo" tabindex="-1">Negativo <a class="header-anchor" href="#negativo" aria-label="Permalink to &quot;Negativo&quot;">​</a></h3><ul><li>Perda do grafo &quot;denso&quot; completo: Não sabemos mais a distância entre dois nós não relacionados (embora, semanticamente, conexões distantes tivessem pouca ou nenhuma utilidade).</li></ul><h2 id="notas" tabindex="-1">Notas <a class="header-anchor" href="#notas" aria-label="Permalink to &quot;Notas&quot;">​</a></h2><ul><li>O script legado <code>nexus_topology.py</code> foi depreciado.</li><li>Protótipo operacional: <code>scripts/build_sparse_topology.py</code> validou a inserção instantânea de 12.000 arestas vs 5.8M.</li></ul>',14)])])}const m=e(i,[["render",r]]);export{h as __pageData,m as default};
